import { Link } from 'react-router-dom';

function Navbar() {
  return (
    <nav>
      <h2>Joy Purveyors</h2>
      <Link to="/">Home</Link>
      <Link to="/about">About</Link>
      <Link to="/services">Services</Link>
      <Link to="/contact">Contact</Link>
      <Link to="/appointment">Book</Link>
    </nav>
  );
}

export default Navbar;
